evaluators.evaluation_logic:
const checkpoints = [];

function parseDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

const conferences = JSON.parse(localStorage.getItem('conferences') || '[]');
const fees = JSON.parse(localStorage.getItem('conference_fees') || '[]');
const bookmarks = JSON.parse(localStorage.getItem('conference_bookmarks') || '[]');

// Identify conferences that match all task criteria
const dateFrom = new Date('2025-09-01T00:00:00Z');
const dateTo = new Date('2025-12-31T23:59:59Z');

const qualifyingConferenceIds = conferences
  .filter((c) => {
    if (!c) return false;
    if (c.region !== 'europe') return false;
    if (!c.isInternational) return false;

    const start = parseDate(c.startDate);
    if (!start || start < dateFrom || start > dateTo) return false;

    const topics = Array.isArray(c.topics)
      ? c.topics.map((t) => String(t).toLowerCase())
      : [];
    const hasAI = topics.some((t) => t.includes('artificial intelligence'));
    if (!hasAI) return false;

    // Check for a student registration fee under or equal to 250 in any currency
    const studentFees = fees.filter(
      (f) => f && f.conferenceId === c.id && f.attendeeType === 'student' && typeof f.amount === 'number'
    );
    if (studentFees.length === 0) return false;
    const minAmount = studentFees.reduce((min, f) => (f.amount < min ? f.amount : min), studentFees[0].amount);
    if (minAmount > 250) return false;

    return true;
  })
  .map((c) => c.id);

// Bookmarks that are actually for qualifying conferences
const qualifyingBookmarks = bookmarks.filter((b) => b && qualifyingConferenceIds.includes(b.conferenceId));

// Single checkpoint: at least one qualifying conference is bookmarked
checkpoints.push({ passed: qualifyingBookmarks.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

const scheduleItems = JSON.parse(localStorage.getItem('personal_schedule_items') || '[]');
const sessions = JSON.parse(localStorage.getItem('conference_sessions') || '[]');

// Group qualifying scheduled sessions by dayIndex
const qualifyingByDay = {};

scheduleItems.forEach((item) => {
  const session = sessions.find((s) => s.id === item.sessionId);
  if (!session) return;

  // Climate-related: explicit flag or keyword containing 'climate'
  let isClimate = session.isClimateRelated === true;
  if (!isClimate && Array.isArray(session.keywords)) {
    isClimate = session.keywords.some((k) => String(k).toLowerCase().includes('climate'));
  }
  if (!isClimate) return;

  // Time between 09:00 and 17:00 (inclusive) in UTC
  const start = parseDate(session.startDateTime);
  const end = parseDate(session.endDateTime);
  if (!start || !end) return;
  const startM = start.getUTCHours() * 60 + start.getUTCMinutes();
  const endM = end.getUTCHours() * 60 + end.getUTCMinutes();
  if (startM < 9 * 60 || endM > 17 * 60) return;

  const dayIndex = session.dayIndex;
  if (typeof dayIndex !== 'number') return;

  if (!qualifyingByDay[dayIndex]) {
    qualifyingByDay[dayIndex] = [];
  }
  qualifyingByDay[dayIndex].push(session);
});

// For each day, only count sessions if there are at least two distinct tracks
let maxQualifyingInDayWithMultiTracks = 0;
Object.keys(qualifyingByDay).forEach((dayKey) => {
  const daySessions = qualifyingByDay[dayKey];
  if (!Array.isArray(daySessions) || daySessions.length === 0) return;
  const trackIds = new Set(daySessions.map((s) => s.trackId).filter(Boolean));
  if (trackIds.size < 2) return; // require multi-track
  if (daySessions.length > maxQualifyingInDayWithMultiTracks) {
    maxQualifyingInDayWithMultiTracks = daySessions.length;
  }
});

// Checkpoints: 1, 2, and 3 qualifying sessions within a single day AND across >=2 tracks
[1, 2, 3].forEach((n, idx) => {
  const weight = n === 3 ? 0.34 : 0.33;
  checkpoints.push({
    passed: maxQualifyingInDayWithMultiTracks >= n,
    weight
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const follows = JSON.parse(localStorage.getItem('followed_researchers') || '[]');
const researchers = JSON.parse(localStorage.getItem('researchers') || '[]');

const qualifyingFollows = follows.filter((f) => {
  const r = researchers.find((rr) => rr.id === f.researcherId);
  if (!r) return false;

  const country = (r.country || '').toLowerCase();
  const affCountry = (r.affiliationCountry || '').toLowerCase();
  if (country !== 'canada' && affCountry !== 'canada') return false;

  if (typeof r.hIndex !== 'number' || r.hIndex < 30 || r.hIndex > 60) return false;

  const expertise = Array.isArray(r.expertiseKeywords)
    ? r.expertiseKeywords.map((e) => String(e).toLowerCase())
    : [];
  const hasMLHealthcare = expertise.some((e) => e.includes('machine learning for healthcare'));
  if (!hasMLHealthcare) return false;

  return true;
});

// Single checkpoint: at least one qualifying researcher followed
checkpoints.push({ passed: qualifyingFollows.length >= 1, weight: 1.0 });

return checkoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

const readingList = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const publications = JSON.parse(localStorage.getItem('publications') || '[]');
const journals = JSON.parse(localStorage.getItem('journals') || '[]');

function getImpactFactor(pub) {
  if (typeof pub.journalImpactFactor === 'number') return pub.journalImpactFactor;
  if (pub.journalId) {
    const j = journals.find((jj) => jj.id === pub.journalId);
    if (j && typeof j.impactFactor === 'number') return j.impactFactor;
  }
  return null;
}

// Find all qualifying publications per task criteria
const qualifyingPubs = publications.filter((p) => {
  if (!p || typeof p.year !== 'number') return false;
  if (p.year < 2021 || p.year > 2024) return false;

  const textParts = [p.title, p.abstract].filter(Boolean).join(' ').toLowerCase();
  const kw = Array.isArray(p.keywords)
    ? p.keywords.map((k) => String(k).toLowerCase())
    : [];
  const hasKeyword = kw.some((k) => k.includes('renewable energy policy')) || textParts.includes('renewable energy policy');
  if (!hasKeyword) return false;

  const isOpen = p.accessType === 'open_access' || p.isOpenAccess === true || (p.accessType === 'hybrid' && p.isOpenAccess === true);
  if (!isOpen) return false;

  const impact = getImpactFactor(p);
  if (impact == null || impact <= 5) return false;

  return true;
});

// Sort by most recent: year desc, then createdAt desc
qualifyingPubs.sort((a, b) => {
  const ya = typeof a.year === 'number' ? a.year : 0;
  const yb = typeof b.year === 'number' ? b.year : 0;
  if (yb !== ya) return yb - ya;
  const da = parseDate(a.createdAt) || new Date(0);
  const db = parseDate(b.createdAt) || new Date(0);
  return db - da;
});

const top3 = qualifyingPubs.slice(0, 3);
const top3Ids = top3.map((p) => p.id);

// How many of these top 3 are in the reading list?
const savedTopCount = top3Ids.filter((pid) => readingList.some((r) => r.publicationId === pid)).length;

// Checkpoints for saving 1, 2, and 3 of the correct top-3 qualifying publications
[1, 2, 3].forEach((n, idx) => {
  const weight = n === 3 ? 0.34 : 0.33;
  checkpoints.push({
    passed: savedTopCount >= n,
    weight
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

const events = JSON.parse(localStorage.getItem('events') || '[]');
const slots = JSON.parse(localStorage.getItem('event_time_slots') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

// Events that match topic, type, duration, and fee criteria
const candidateEvents = events.filter((e) => {
  if (!e) return false;
  if (e.eventType !== 'workshop') return false;
  if (e.durationType !== 'half_day') return false;
  if (typeof e.baseFeeAmount !== 'number' || e.baseFeeAmount > 150) return false;
  const topics = Array.isArray(e.topics)
    ? e.topics.map((t) => String(t).toLowerCase())
    : [];
  const hasDataViz = topics.some((t) => t.includes('data visualization'));
  if (!hasDataViz) return false;
  return true;
});

const candidateEventIds = candidateEvents.map((e) => e.id);

const qualifyingRegs = regs.filter((r) => {
  if (!r) return false;
  if (!candidateEventIds.includes(r.eventId)) return false;

  // Must be guest registration
  if (r.registrationType !== 'guest') return false;

  // Avoid immediate online payment
  if (r.paymentOption === 'pay_online') return false;

  // Pre-registration indicator (BusinessLogic defaults this to true for drafts)
  if (r.isPreRegistration === false) return false;

  const eventSlots = slots.filter((s) => s.eventId === r.eventId);

  // If multiple time slots exist, require earliest (morning) slot
  if (eventSlots.length > 1) {
    if (!r.timeSlotId) return false;
    let earliestMinutes = null;
    eventSlots.forEach((s) => {
      const d = parseDate(s.startDateTime);
      if (!d) return;
      const m = d.getUTCHours() * 60 + d.getUTCMinutes();
      if (earliestMinutes === null || m < earliestMinutes) {
        earliestMinutes = m;
      }
    });
    if (earliestMinutes === null) return false;
    const earliestSlotIds = eventSlots
      .filter((s) => {
        const d = parseDate(s.startDateTime);
        if (!d) return false;
        const m = d.getUTCHours() * 60 + d.getUTCMinutes();
        return m === earliestMinutes;
      })
      .map((s) => s.id);
    if (!earliestSlotIds.includes(r.timeSlotId)) return false;
  }

  return true;
});

// Single checkpoint: at least one qualifying pre-registration matching all criteria
checkpoints.push({ passed: qualifyingRegs.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

let hasQualifyingEmail = false;

// Group by email and check for both topics with correct settings
const byEmail = {};
subs.forEach((s) => {
  if (!s || !s.email) return;
  if (!byEmail[s.email]) byEmail[s.email] = [];
  byEmail[s.email].push(s);
});

Object.keys(byEmail).forEach((email) => {
  const list = byEmail[email];
  const ai = list.find(
    (s) => s.topic === 'ai_ethics' && s.isActive && s.frequency === 'weekly' && s.format === 'html'
  );
  const climate = list.find(
    (s) => s.topic === 'climate_policy' && s.isActive && s.frequency === 'weekly' && s.format === 'html'
  );
  if (ai && climate) {
    hasQualifyingEmail = true;
  }
});

// Single checkpoint: at least one email address with both required subscriptions configured correctly
checkpoints.push({ passed: hasQualifyingEmail, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const donations = JSON.parse(localStorage.getItem('donations') || '[]');
const programs = JSON.parse(localStorage.getItem('donation_programs') || '[]');

// Identify early-career research grants programs
const earlyCareerProgramIds = programs
  .filter((p) => p && (p.code === 'early_career_research_grants' || String(p.name || '').toLowerCase().includes('early career research grants')))
  .map((p) => p.id);

const qualifyingDonations = donations.filter((d) => {
  if (!d) return false;
  if (d.donationType !== 'one_time') return false;
  if (d.amount !== 75) return false;
  if (d.currency !== 'usd') return false;
  if (!earlyCareerProgramIds.includes(d.programId)) return false;
  if (!d.isAnonymous) return false;
  // Opt out of physical mail
  if (d.communicationPreference !== 'no_postal_mail') return false;
  // Draft/pending payment only (no completed donation)
  if (d.status !== 'pending_payment' && d.status !== 'draft') return false;
  return true;
});

// Single checkpoint: at least one qualifying donation draft created
checkpoints.push({ passed: qualifyingDonations.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('membership_plans') || '[]');
const applications = JSON.parse(localStorage.getItem('membership_applications') || '[]');

// Relevant individual plans that include both required benefits
const relevantPlans = plans.filter((p) => {
  if (!p) return false;
  if (p.isActive === false) return false;
  if (p.planType !== 'student' && p.planType !== 'professional') return false;
  if (!p.includesMemberWebinars) return false;
  if (!p.includesDiscountedConferenceFees) return false;
  return true;
});

let chosenCorrectly = false;

if (relevantPlans.length > 0) {
  // Determine the cheapest eligible plan
  let cheapest = relevantPlans[0];
  relevantPlans.slice(1).forEach((p) => {
    if (typeof p.annualPriceAmount === 'number' && p.annualPriceAmount < cheapest.annualPriceAmount) {
      cheapest = p;
    }
  });

  // Check if there is an application for this cheapest plan
  const hasAppForCheapest = applications.some(
    (a) => a && a.planId === cheapest.id && a.status === 'in_progress'
  );

  if (hasAppForCheapest) {
    chosenCorrectly = true;
  }
}

// Single checkpoint: user started an application for the correct (cheapest qualifying) plan
checkpoints.push({ passed: chosenCorrectly, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
